import { Button } from '@semparar/design-system-app';
import React from 'react';

import { usePreventDoubleClick } from '../../../hooks/usePreventDoubleClick';
import { PreventDoubleClickButtonProps } from './Models';

export const PreventDoubleClickButton: React.FC<
  PreventDoubleClickButtonProps
> = ({
  onPress,
  preventDoubleClickDelay = 1000,
  onDoubleClickAttempt,
  showLoadingIndicator = false,
  disabled,
  ...rest
}) => {
  const { executeWithPreventDoubleClick, isProcessing } = usePreventDoubleClick(
    onPress || (() => {}),
    {
      delay: preventDoubleClickDelay,
      onDoubleClickAttempt,
    },
  );

  const isDisabled = disabled || isProcessing;

  return (
    <Button
      {...rest}
      disabled={isDisabled}
      onPress={onPress ? executeWithPreventDoubleClick : undefined}
    />
  );
};

