    14â†’  const benefitList = useMemo<PropsCardActivityExtended[]>(
    15â†’    () =>
    16â†’      Object.entries(benefits ?? {})
    17â†’        ?.filter(([_, { idTitle, idText, idFullTitle, idFullText, idIcone, idType }]) => {
    18â†’          return (
    19â†’            !!idTitle?.text &&
    20â†’            !!idText?.text &&
    21â†’            !!idFullTitle?.text &&
    22â†’            !!idFullText?.text &&
    23â†’            !!idIcone?.text &&
    24â†’            !!idType?.text
    25â†’          );
    26â†’        })
    27â†’        ?.map(
    28â†’          ([_, value]) =>
    29â†’            ({
    30â†’              onPress: () => {
    31â†’                itemOnPress(value);
    32â†’              },
    33â†’              showIcon: true,
    34â†’              hideBorder: true,
    35â†’              title: value.idTitle?.text,
    36â†’              description: value.idText?.text,
    37â†’              icon: value.idIcone?.text,
    38â†’              priority: Number(value.idPriority?.text) || 0,
    39â†’              showTagLabel: !!value?.idTagCard?.text,
    40â†’              textTagLabel: capitalizeFirstLetters(value?.idTagCard?.text),
    41â†’              typeTagLabel: 'neutral',
    42â†’              highlightTagLabel: !!value?.idTagCard?.text,
    43â†’            } as PropsCardActivityExtended)
    44â†’        )
    45â†’        .sort((a, b) => (a.priority ?? 0) - (b.priority ?? 0)),
    46â†’    [benefits, itemOnPress]
    47â†’  );
    48â†’
    49â†’  return (
    50â†’    <FlatList
    51â†’      data={benefitList}
    52â†’      keyExtractor={(item) => item.priority.toString()}
    53â†’      renderItem={({ item }) => {
